init_eqs:
// Beat Detective v0.07--
sb_brate = 1; sb_rate = 1; sb_stime = time; sb_res = 0; res = 0;
old_bass = bass_att;

frame_eqs:
chng = (rand(100)/100);
icount = if(equal(chng,0),(icount+1),icount);
irun = if(above(icount,5),0,chng);

sb_brate = if(irun,bass_rate,sb_brate);
sb_rate = if(irun,rate,sb_rate);
sb_stime = if(irun,time,sb_stime);
dt = if(irun,time-sb_stime, dt); //due to a phase shift of the sin wave, due to an initial phase shift of -PI/2, we add 2PI to make sure we start with rising values of the sin wave. This happens only once at the beginning of the detection process.

bc = bc+above(dif,0); //count every rise
dc = dc+below(dif,0); //count every fall
sb_res = if(irun,res,sb_res);
res = if(above(abs(dif),sb_res),abs(dif),res);

old_bass = bass_att;

di = (bc-dc)*0.02; //difference in amount of rises and falls - higher value means more beats detected
dif = (bass_att-old_bass)*50;
dif = dif+dif*0.01*di; //add a little bit of difference to bass values so that they don't get stuck at local maxima
beat = above(abs(dif),res*0.75);
bass_changed = if(beat,bass_changed+0.01,bass_changed);
bass_changed = bass_changed*below(bass_changed,0.999); //decay
// Beat Detective v0.07--

q8 = beat;
warp = 0;
ob_r = 0.5 + 0.5*sin(0.437*time+1);
ob_g = 0.5 + 0.5*sin(0.544*time+2);
ob_b = 0.5 + 0.5*sin(0.751*time+3);

q6 = q6*(q6 == 0) + ((frame%4 == 0) * (rand(100) / 100) * 0.02);
zoom = zoom + 0.05;

decay = decay - 0.01*(frame%10 == 0);

wave_0_per_point:
ma=ma+(above(bass,1)*3.1415*.01*bass);
ma=ma-(above(treb,1)*3.1415*.01*treb);

mx=mx+(.0002*cos(ma));
my=my+(.0002*sin(ma));

mx=if(above(mx,.9),(.9-mx),mx);
my=if(above(my,.9),(.9-my),my);
mx=if(below(mx,.1),(.9+mx),mx);
my=if(below(my,.1),(.9+my),my);

x=mx;
y=my;

a=(above(bass+mid+treb,.8));

